import json
import os

def build_mock_protein_db():
    """Build a mock UniProt toxin database for the hackathon."""
    # In reality, this would be a large JSON built from UniProt
    
    db = {
        "P13423": {
            "name": "Protective antigen (PA)",
            "organism": "Bacillus anthracis",
            "function": "Binds to host cell receptors and mediates entry of edema factor and lethal factor.",
            "sequence": ""
        },
        "P0DTC2": {
            "name": "Spike glycoprotein",
            "organism": "Severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2)",
            "function": "Viral entry into host cells by binding to ACE2 receptor.",
            "sequence": ""
        }
    }
    
    os.makedirs(os.path.dirname(os.path.abspath(__file__)), exist_ok=True)
    out_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "uniprot_toxins.json")
    
    with open(out_path, 'w') as f:
        json.dump(db, f, indent=2)
        
    print(f"Built mock protein database at {out_path} with {len(db)} proteins.")

if __name__ == "__main__":
    build_mock_protein_db()
